// Duplicate message protection using workflow static data (production-safe, fail-open)
// This blocks the vast majority of duplicate webhook deliveries from Meta (formal
// retries, delayed re-sends that arrive after this workflow has already finished
// once). It is paired with "Send Guard" right before the WhatsApp send, which is
// the tighter of the two checks. Kept intentionally lean (capped size + time-based
// expiry below) so this lookup stays fast on every single execution, forever вЂ”
// a bloated cache here slows down every future run and widens the collision window.
try {
  const body = $input.first().json.body;
  const messageId = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.id;

  // No message ID means status update or malformed вЂ” pass through for filtering
  if (!messageId) {
    return [{ json: $input.first().json }];
  }

  // Get global static data cache
  const cache = $getWorkflowStaticData('global');
  if (!cache.processedMessages) {
    cache.processedMessages = {};
  }

  const now = Date.now();
  const MAX_AGE_MS = 6 * 60 * 60 * 1000; // 6 hours is plenty вЂ” real duplicates arrive within seconds/minutes
  const MAX_ENTRIES = 300;

  // Housekeeping: only runs once the cache actually grows, first by age then by size.
  const keys = Object.keys(cache.processedMessages);
  if (keys.length > MAX_ENTRIES) {
    for (const k of keys) {
      if (now - cache.processedMessages[k] > MAX_AGE_MS) {
        delete cache.processedMessages[k];
      }
    }
    const remaining = Object.keys(cache.processedMessages);
    if (remaining.length > MAX_ENTRIES) {
      const sorted = remaining.sort((a, b) => cache.processedMessages[a] - cache.processedMessages[b]);
      for (let i = 0; i < sorted.length - MAX_ENTRIES; i++) {
        delete cache.processedMessages[sorted[i]];
      }
    }
  }

  // Duplicate check
  if (cache.processedMessages[messageId]) {
    return []; // Stop вЂ” already processed, prevents duplicate replies from Meta retries
  }

  // Mark as processed and continue
  cache.processedMessages[messageId] = now;
  return [{ json: $input.first().json }];
} catch (err) {
  // Fail-open: never block a real message because of an internal dedup error
  console.log(JSON.stringify({ ts: new Date().toISOString(), dedupGuardError: String(err && err.message ? err.message : err) }));
  return [{ json: $input.first().json }];
}

// Production-safe Meta WhatsApp Cloud payload parser вЂ” never throws
try {
  const body = $input.first().json.body;
  const value = body?.entry?.[0]?.changes?.[0]?.value;

  // Ignore status events, delivery receipts, read receipts etc.
  if (!value?.messages?.length) {
    return [];
  }

  const msg = value.messages[0];
  const contact = value.contacts?.[0];

  let messageText = "";
  let mediaId = null;
  let mediaCaption = null;
  let location = null;
  let contactsShared = null;

  switch (msg.type) {
    case "text":
      messageText = msg.text?.body || "";
      break;

    case "interactive":
      if (msg.interactive?.type === "button_reply") {
        messageText = msg.interactive.button_reply?.title || "[button reply]";
      } else if (msg.interactive?.type === "list_reply") {
        messageText = msg.interactive.list_reply?.title || "[list reply]";
      } else {
        messageText =
          msg.interactive?.button_reply?.title ||
          msg.interactive?.list_reply?.title ||
          "[interactive]";
      }
      break;

    case "button":
      messageText = msg.button?.text || "[button]";
      break;

    case "image":
      mediaId = msg.image?.id || null;
      mediaCaption = msg.image?.caption || "";
      messageText = mediaCaption ? `[image] ${mediaCaption}` : "[image]";
      break;

    case "document":
      mediaId = msg.document?.id || null;
      mediaCaption = msg.document?.caption || msg.document?.filename || "";
      messageText = mediaCaption ? `[document] ${mediaCaption}` : "[document]";
      break;

    case "audio":
      mediaId = msg.audio?.id || null;
      messageText = "[audio message]";
      break;

    case "voice":
      mediaId = msg.voice?.id || null;
      messageText = "[voice message]";
      break;

    case "video":
      mediaId = msg.video?.id || null;
      mediaCaption = msg.video?.caption || "";
      messageText = mediaCaption ? `[video] ${mediaCaption}` : "[video]";
      break;

    case "sticker":
      mediaId = msg.sticker?.id || null;
      messageText = "[sticker]";
      break;

    case "location":
      location = {
        latitude: msg.location?.latitude ?? null,
        longitude: msg.location?.longitude ?? null,
        name: msg.location?.name || "",
        address: msg.location?.address || ""
      };
      messageText = `[location] ${location.name || ""} ${location.address || ""}`.trim() || "[location shared]";
      break;

    case "contacts":
      contactsShared = msg.contacts || [];
      messageText = "[contact shared]";
      break;

    default:
      messageText = `[unsupported message type: ${msg.type || "unknown"}]`;
  }

  return [
    {
      json: {
        phone: msg.from,
        profileName: contact?.profile?.name || "",
        message: messageText,
        messageId: msg.id,
        messageType: msg.type || "unknown",
        mediaId,
        mediaCaption,
        location,
        contactsShared,
        timestamp: msg.timestamp,
        phoneNumberId: value.metadata?.phone_number_id,
        wa_id: contact?.wa_id || msg.from
      }
    }
  ];
} catch (err) {
  // Never throw вЂ” always return a safe, loggable fallback item
  console.log(JSON.stringify({ ts: new Date().toISOString(), extractDataError: String(err && err.message ? err.message : err) }));
  return [
    {
      json: {
        phone: null,
        profileName: "",
        message: "[unparsed message]",
        messageId: null,
        messageType: "unknown",
        mediaId: null,
        mediaCaption: null,
        location: null,
        contactsShared: null,
        timestamp: null,
        phoneNumberId: null,
        wa_id: null,
        error: String(err && err.message ? err.message : err)
      }
    }
  ];
}

