// Structured, production-safe execution log вЂ” never throws, never blocks the workflow
try {
  let extract = {};
  try { extract = $('Extract Data').item.json || {}; } catch (e) { extract = {}; }

  let aiReply = null;
  try { aiReply = $('Prepare Reply').item.json.replyText; } catch (e) { aiReply = null; }

  let sendRes = {};
  try { sendRes = $input.first().json || {}; } catch (e) { sendRes = {}; }

  const log = {
    ts: new Date().toISOString(),
    customer: { phone: extract.phone || null, name: extract.profileName || '', msgType: extract.messageType || 'unknown' },
    inbound: extract.message || null,
    aiReply: aiReply,
    sent: !!(sendRes && sendRes.messages),
    metaMsgId: sendRes?.messages?.[0]?.id || null,
    error: sendRes?.error || null
  };

  console.log(JSON.stringify(log));
} catch (err) {
  console.log(JSON.stringify({ ts: new Date().toISOString(), loggerError: String(err && err.message ? err.message : err) }));
}

return [{ json: { status: 'EVENT_LOGGED' } }];

// Status/receipt event (sent, delivered, read, etc.) вЂ” safely ignored, never throws
try {
  console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'non_message_event_ignored' }));
} catch (err) {
  // never throw
}
return [{ json: { status: 'IGNORED_NON_MESSAGE_EVENT' } }];

// Safely normalize the AI Agent output before sending to WhatsApp - never throws.
// Also strips REPEATED lines/sentences: the n8n LangChain agent can concatenate
// near-identical text from multiple tool-loop iterations into one output, which
// looks like the bot spamming the same sentence 4-5 times. We keep only the
// first occurrence of each (normalized) line so the customer always gets a
// clean, human-looking single reply.
const FALLBACK = "Sorry, we hit a small technical issue. Please send your message again in a moment.";
try {
  const aiItem = $input.first().json;
  let replyText = aiItem?.output;

  if (typeof replyText !== "string" || !replyText.trim()) {
    replyText = FALLBACK;
  }

  // Normalize a line for comparison: lowercase, strip punctuation/whitespace
  const normalize = (s) => s.toLowerCase().replace(/[^a-z0-9\u0900-\u097F]+/gi, " ").trim();

  // 1) Dedupe by line
  const seen = new Set();
  const lines = replyText.split("\n");
  const keptLines = [];
  for (const line of lines) {
    const key = normalize(line);
    if (!key) { keptLines.push(line); continue; } // keep blank lines for formatting
    if (seen.has(key)) continue;                   // skip exact repeated line
    seen.add(key);
    keptLines.push(line);
  }
  replyText = keptLines.join("\n");

  // 2) Dedupe by sentence within the whole reply (catches repeats on one line)
  const sentSeen = new Set();
  const parts = replyText.split(/(?<=[.!?\u0964])\s+/);
  if (parts.length > 1) {
    const keptSents = [];
    for (const p of parts) {
      const key = normalize(p);
      if (key && key.split(" ").length >= 4) {     // only dedupe real sentences, not short fragments
        if (sentSeen.has(key)) continue;
        sentSeen.add(key);
      }
      keptSents.push(p);
    }
    replyText = keptSents.join(" ").replace(/[ \t]+\n/g, "\n").trim();
  }

  // 3) Collapse 3+ blank lines left behind by removals
  replyText = replyText.replace(/\n{3,}/g, "\n\n").trim();

  if (!replyText) {
    replyText = FALLBACK;
  }

  return [{ json: { replyText } }];
} catch (err) {
  return [{ json: { replyText: FALLBACK } }];
}

// FINAL duplicate-send protection вЂ” runs immediately before the WhatsApp API call.
// Even if a duplicate webhook delivery slipped past Dedup Guard earlier in the flow
// (e.g. it arrived while this exact message was still being handled by the AI Agent),
// this guarantees at most ONE outbound WhatsApp message per unique inbound message ID.
// Kept intentionally lean (capped size + time-based expiry below) so the lookup stays
// fast on every execution, forever вЂ” a bloated cache slows every future run down and
// widens the collision window for the next message.
// Fail-open: never blocks a real reply because of an internal error.
try {
  const messageId = $('Extract Data').first().json.messageId;

  if (!messageId) {
    // No message ID to key off вЂ” allow the send rather than risk silently dropping a real reply
    return [{ json: $input.first().json }];
  }

  const cache = $getWorkflowStaticData('global');
  if (!cache.sentReplies) {
    cache.sentReplies = {};
  }

  const now = Date.now();
  const MAX_AGE_MS = 6 * 60 * 60 * 1000; // 6 hours is plenty вЂ” real duplicates arrive within seconds/minutes
  const MAX_ENTRIES = 300;

  // Housekeeping: only runs once the cache actually grows, first by age then by size.
  const keys = Object.keys(cache.sentReplies);
  if (keys.length > MAX_ENTRIES) {
    for (const k of keys) {
      if (now - cache.sentReplies[k] > MAX_AGE_MS) {
        delete cache.sentReplies[k];
      }
    }
    const remaining = Object.keys(cache.sentReplies);
    if (remaining.length > MAX_ENTRIES) {
      const sorted = remaining.sort((a, b) => cache.sentReplies[a] - cache.sentReplies[b]);
      for (let i = 0; i < sorted.length - MAX_ENTRIES; i++) {
        delete cache.sentReplies[sorted[i]];
      }
    }
  }

  if (cache.sentReplies[messageId]) {
    // A reply for this exact inbound message has already been sent вЂ” stop here
    console.log(JSON.stringify({ ts: new Date().toISOString(), sendGuardBlocked: messageId }));
    return [];
  }

  cache.sentReplies[messageId] = now;
  return [{ json: $input.first().json }];
} catch (err) {
  console.log(JSON.stringify({ ts: new Date().toISOString(), sendGuardError: String(err && err.message ? err.message : err) }));
  return [{ json: $input.first().json }];
}

// Fetch contact phone number from Supabase for CRM agent reply
// Env vars: SUPABASE_URL, SUPABASE_SERVICE_KEY, WORKSPACE_ID
try {
  const body = $input.first().json.body || $input.first().json;
  const { conversation_id, workspace_id, agent_id, message, timestamp } = body;

  if (!conversation_id || !message) {
    return [{ json: { error: 'Missing conversation_id or message', ok: false } }];
  }

  const SB_URL = $env.SUPABASE_URL;
  const SB_KEY = $env.SUPABASE_SERVICE_KEY;

  if (typeof fetch === 'undefined') {
    console.log(JSON.stringify({ ts: new Date().toISOString(), node: 'CRM Prepare Send', skip: 'fetch unavailable' }));
    return [{ json: { ok: false, error: 'fetch unavailable' } }];
  }
  if (!SB_URL || !SB_KEY) {
    return [{ json: { error: 'Supabase env vars not configured', ok: false } }];
  }

// 5-second timeout wrapper вЂ” prevents hanging if Supabase is unreachable
  function withTimeout(promise, ms) {
    return Promise.race([
      promise,
      new Promise((_, reject) => setTimeout(() => reject(new Error('CRM fetch timeout')), ms))
    ]);
  }
  async function sbFetch(url, opts) {
    for (let attempt = 0; attempt < 2; attempt++) {
      try { return await withTimeout(fetch(url, opts), 5000); } catch (e) {
        if (attempt === 1) throw e;
        await new Promise(r => setTimeout(r, 500));
      }
    }
  }

  const headers = {
    'Content-Type': 'application/json',
    apikey: SB_KEY,
    Authorization: `Bearer ${SB_KEY}`
  };

  // Fetch conversation with contact phone (Supabase foreign-key join)
  const convRes = await sbFetch(
    `${SB_URL}/rest/v1/conversations?id=eq.${conversation_id}&select=id,contact_id,contacts(phone_number,name)`,
    { headers }
  );
  const convs = await convRes.json();

  if (!Array.isArray(convs) || !convs.length || !convs[0].contacts?.phone_number) {
    return [{ json: { error: 'Conversation or contact not found', conversation_id, ok: false } }];
  }

  return [{ json: {
    ok: true,
    conversation_id,
    workspace_id: workspace_id || $env.WORKSPACE_ID || '',
    agent_id: agent_id || '',
    message: (message || '').trim(),
    timestamp: timestamp || new Date().toISOString(),
    phone: convs[0].contacts.phone_number,
    contactName: convs[0].contacts.name || convs[0].contacts.phone_number
  }}];
} catch (err) {
  console.log(JSON.stringify({ ts: new Date().toISOString(), crmPrepareErr: String(err?.message || err) }));
  return [{ json: { error: String(err?.message || err), ok: false } }];
}

